# Shape hierarchy module with interface, abstract class, and concrete implementations

interface Drawable:
    def draw(self) -> str
    ...

@abstract
class Shape(Drawable):
    _name: str

    @abstract
    def area(self) -> float:
        ...

    @virtual
    def describe(self) -> str:
        return "Shape: " + self._name

class Circle(Shape):
    _radius: float

    def __init__(self, radius: float):
        super().__init__()
        self._name = "circle"
        self._radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self._radius * self._radius

    @override
    def draw(self) -> str:
        return "Drawing circle with radius " + str(self._radius)

    property get radius(self) -> float:
        return self._radius

class Rectangle(Shape):
    _width: float
    _height: float

    def __init__(self, width: float, height: float):
        super().__init__()
        self._name = "rectangle"
        self._width = width
        self._height = height

    @override
    def area(self) -> float:
        return self._width * self._height

    @override
    def draw(self) -> str:
        return "Drawing rectangle " + str(self._width) + " x " + str(self._height)

    def is_square(self) -> bool:
        return self._width == self._height

